import type { SideNavBar } from "../../componentTypes/sideNavBar"
import type { Semantics } from "../semantics"

const sideNavBar = (semantics: Semantics): SideNavBar => ({
  backgroundColor: semantics.color.background.elevatedSurface.base,
  fill: semantics.color.icon.interactive.action.primaryOnColor.base,
  fontColor: semantics.color.text.base,
  minimizedWidth: "3.75rem",
  toggleTransition: "300ms",
  width: "5.875rem",
  margin: semantics.spacing.spaceMd,
  minimizedMargin: "0.375rem",
  contentMargin: "0.375rem",
  contentGap: semantics.spacing.spaceXs,
  boxShadow: {
    0: {
      x: "0rem",
      y: "0.0625rem",
      blur: "0.125rem",
      spread: "0rem",
      color: semantics.color.dropShadow.shadowColor1,
      type: "dropShadow",
    },
    1: {
      x: "0rem",
      y: "0.125rem",
      blur: "0.25rem",
      spread: "0.125rem",
      color: semantics.color.dropShadow.shadowColor2,
      type: "dropShadow",
    },
  },
  borderRadius: semantics.borderRadius.container.md,
  minimizedBorderRadius: semantics.borderRadius.container.sm,
})
